const item = $input.first().json;
const root = item.body ?? item;
const event = root.event ?? item.event ?? "";

function getInstance(payload) {
  return (
    payload?.instance ||
    payload?.instanceName ||
    payload?.data?.instance ||
    payload?.data?.instanceName ||
    payload?.eventData?.instance ||
    payload?.eventData?.instanceName ||
    ""
  );
}

const instance_name = String(getInstance(root) || "").trim();
const data = root.data ?? {};
const numero_clinica = String(
  root.numero_clinica ??
  data.numero_clinica ??
  item.headers?.["x-numero-clinica"] ??
  ""
).trim();

let patient_phone_e164 = "";
let message_text = "";
let connection_state = "";

function jidToDigits(jid) {
  if (!jid || typeof jid !== "string") return "";
  const user = jid.split("@")[0];
  return user.split(":")[0].replace(/\D/g, "");
}

function extractText(m) {
  if (!m || typeof m !== "object") return "";
  if (m.conversation) return String(m.conversation);
  if (m.extendedTextMessage?.text) return String(m.extendedTextMessage.text);
  if (m.imageMessage?.caption) return String(m.imageMessage.caption);
  return "";
}

if (event === "MESSAGES_UPSERT") {
  let payload = data;
  if (Array.isArray(payload)) payload = payload[0];
  if (payload?.messages?.[0]) payload = payload.messages[0];
  const key = payload.key ?? payload?.message?.key;
  if (key?.fromMe === true) return [];
  const remoteJid = key?.remoteJid || payload.remoteJid || "";
  const waDigits = jidToDigits(remoteJid);
  if (!waDigits) return [];
  patient_phone_e164 = "+" + waDigits;
  const msgObj = payload.message ?? payload;
  message_text = extractText(msgObj).trim();
}

if (event === "CONNECTION_UPDATE") {
  connection_state = String(data.state ?? root.state ?? "").toLowerCase();
}

return [{
  json: {
    event,
    instance_name,
    numero_clinica,
    patient_phone_e164,
    message_text,
    connection_state,
    raw: root,
  },
}];

// Valida resultado da RPC n8n_resolve_clinic e mescla com dados do normalizador.
// Colocado ANTES do Switch: Assinatura para garantir que cenario está sempre definido
// e para que todos os ramos (inclusive os de bloqueio) tenham acesso a instance_name
// e patient_phone_e164 sem precisar referenciar outros nós.
//
// Campos herdados do normalizador (norm):
//   event, instance_name, numero_clinica, patient_phone_e164, message_text,
//   connection_state, raw
//
// Campos retornados pela RPC (row):
//   found, erro, clinica_id, instance_name, numero_clinica, clinica_ativa,
//   tipo_plano, data_expiracao, inadimplente, whatsapp_status,
//   clinica_nome, agent_instructions, cenario
//
// Em caso de colisão, campos da RPC têm precedência (exceto cenario, que é
// sempre normalizado abaixo).

const items = $input.all();
const norm = $('Code: Normalizar Webhook').first().json;

if (!items || items.length === 0 || !items[0].json) {
  return [{ json: {
    ...norm,
    found: false,
    erro: 'not_found',
    cenario: 'clinica_nao_encontrada',
    clinica_id: null,
    clinica_nome: null,
    agent_instructions: null,
  }}];
}

const row = items[0].json;
const cenario = row.cenario || 'clinica_nao_encontrada';

return [{ json: { ...norm, ...row, cenario } }];

// $input vem de Buscar Histórico (contém { historico: [...] })
// Contexto da clínica e do paciente vêm de Code: Processar Resultado RPC
const base = $('Code: Processar Resultado RPC').first().json;
const histRow = $input.first().json;
const row = { ...base, ...histRow };

let historicoRaw = row.historico;
if (typeof historicoRaw === 'string') {
  try { historicoRaw = JSON.parse(historicoRaw); } catch { historicoRaw = []; }
}
const historico = Array.isArray(historicoRaw) ? historicoRaw : [];
const historicoLimitado = historico.slice(-20);
const historicoFormatado = historicoLimitado
  .map((msg) => `${msg.role === 'user' ? 'Paciente' : 'Agente'}: ${msg.content}`)
  .join('\n');

const agentText = row.agent_instructions || '';
const nome = row.clinica_nome || '';
const systemPrompt = `${agentText}\n\n## Contexto da Clínica\nClínica: ${nome}\nTelefone do Paciente: ${row.patient_phone_e164}\nData/Hora: ${new Date().toLocaleString('pt-BR')}\n\n## Histórico da Conversa\n${historicoFormatado}\n\n## Instruções Críticas\n- Responda sempre como agente de IA da clínica\n- Mantenha tom profissional mas acolhedor\n- Se não souber responder, ofereça contato direto com a clínica\n- Não invente dados do paciente\n- Respeite privacidade e confidencialidade`;

return [{
  json: {
    systemPrompt,
    mensagemPaciente: row.message_text,
    telefonePaciente: row.patient_phone_e164,
    historicoLimitado,
    clinicaId: row.clinica_id,
    nomeInstancia: row.instance_name,
  }
}];

// $input vem de Enviar Mensagem Evolution (resposta HTTP da Evolution API)
// Dados do contexto vêm de Code: Montar Prompt e Claude API
const promptData = $('Code: Montar Prompt').first().json;
const claudeOutput = $('Claude API').first().json;

// Extrai texto da resposta da Anthropic Messages API
// Suporta content[] (formato atual) e campos legados text/output
const claudeText =
  (claudeOutput.content || [])
    .filter(b => b.type === 'text')
    .map(b => b.text || '')
    .join('') ||
  claudeOutput.text ||
  claudeOutput.output ||
  '';

const novoHistorico = [...(promptData.historicoLimitado || [])];
novoHistorico.push({
  role: 'user',
  content: promptData.mensagemPaciente,
  timestamp: new Date().toISOString(),
});
novoHistorico.push({
  role: 'assistant',
  content: claudeText,
  timestamp: new Date().toISOString(),
});
const historicoFinal = novoHistorico.slice(-20);

return [{
  json: {
    clinicaId: promptData.clinicaId,
    telefonePaciente: promptData.telefonePaciente,
    historico: JSON.stringify(historicoFinal),
  }
}];

const norm = $input.first().json;
const state = String(norm.connection_state || norm.raw?.data?.state || '').toLowerCase();
const instance = norm.instance_name || '';
const statusWhatsapp = state === 'open' ? 'connected' : 'disconnected';
return [{ json: { statusWhatsapp, instance } }];
